public class RazredA { 
   static int x = 3; 
   int y; 
   RazredA() { 
      x++ ; 
      y++ ; 
   } 
   static void metodaA(int i, int i2){ 
      x = x + i + i2; 
      System.out.println("x=" + x); 
   } 
   public static void main(String[] args) { 
      RazredA a1 = new RazredA(); 
      RazredA.metodaA(3,2); 
      RazredA a2 = new RazredA(); 
      RazredA.metodaA(4,2); 
    } 
}

